'use strict';

const defaults = {
  smoke_mode: true,
  pkm_test_mode: true,
  calendar_test_mode: true,
  smoke_telegram_dry_run: true,
  telegram_test_chat_id: '1509032341',
  test_calendar_id: '831dca29672745da07709e8636e37b6241df174fca270982c66a046b915b2dc1@group.calendar.google.com',
  prod_calendar_id: 'pkm.gasovic@gmail.com',
  allow_test_calendar_purge: false,
  public_ingress_path: 'pkm/smoke/ingress',
};
const now = new Date();
const pad = (v) => String(v).padStart(2, '0');
const runId = [
  'smoke',
  now.getUTCFullYear(),
  pad(now.getUTCMonth() + 1),
  pad(now.getUTCDate()),
  pad(now.getUTCHours()) + pad(now.getUTCMinutes()) + pad(now.getUTCSeconds()),
].join('_');

return [{
  json: {
    ...defaults,
    test_run_id: runId,
    started_at: now.toISOString(),
    results: [],
    artifacts: {},
    smoke_mode: true,
    pkm_test_mode: true,
    calendar_test_mode: true,
  },
}];

'use strict';

const base = { ...$json };
const results = Array.isArray(base.results) ? [...base.results] : [];
const headers = { 'X-PKM-Run-Id': String(base.test_run_id || '') };
let prior = null;
let ok = false;
let error = null;

try {
  const stateRows = await helpers.httpRequest({
    method: 'GET',
    url: 'http://pkm-server:8080/db/test-mode',
    headers,
    json: true,
  });
  const first = Array.isArray(stateRows) ? stateRows[0] : null;
  prior = !!(first && first.is_test_mode === true);

  if (!prior) {
    await helpers.httpRequest({
      method: 'POST',
      url: 'http://pkm-server:8080/db/test-mode/toggle',
      headers,
      json: true,
      body: {},
    });
  }
  ok = true;
} catch (e) {
  error = { message: String(e && e.message ? e.message : e) };
}

results.push({
  test_case: 'T00-test-mode-setup',
  ok,
  run_id: base.test_run_id || null,
  artifacts: { prior_test_mode: prior },
  assertions: [
    { name: 'test_mode_state_read', ok: prior !== null },
    { name: 'test_mode_enabled_for_run', ok },
  ],
  error,
});

return [{ json: { ...base, prior_test_mode: prior, results } }];

